import { LiquidEther } from '@/sd-components/36039875-1e54-4edb-8860-9609381fb61c';

function MyComponent() {
  return (
    <div style={{ width: '100vw', height: '100vh' }}>
      <LiquidEther 
        colors={['#000000', '#3b82f6', '#ffffff']}
        mouseForce={25}
        autoDemo={true}
      />
    </div>
  );
}
