  ]
}

{
  "summary": "A sophisticated editorial-style UI featuring a fixed background grid, high-contrast serif typography, and technical monospace accents with a muted forest green primary color.",
  "style": {
    "description": "The design uses a trio of typefaces: Playfair Display (Serif) for headers and emotional impact, Space Grotesk (Sans) for readability, and Space Mono (Mono) for all technical data, labels, and buttons. The color palette is organic and muted: Background (#f7f6f2), Foreground (#1c1c1c), and Primary Accent (#3d7068). Layouts are governed by a strict 4-column vertical guide system and 1px borders. Transitions use a custom 'editorial' cubic-bezier(0.16, 1, 0.3, 1) for a smooth, high-fashion feel.",
    "prompt": "Apply an editorial tech aesthetic using background #f7f6f2 and foreground #1c1c1c. Typography: Headings in 'Playfair Display' (light weight, tight tracking), UI labels and buttons in 'Space Mono' (uppercase, tracking 0.2em-0.3em), and body text in 'Space Grotesk'. Use #3d7068 as the primary accent color for buttons and highlights. Implement 1px borders using #e5e4de. All animations must use cubic-bezier(0.16, 1, 0.3, 1) with a 700ms-1000ms duration. Include a fixed background grid of 40px squares with a radial mask that fades toward the edges."
  },
  "layout_and_structure": {
    "description": "The layout is built on a max-width 7xl container with visible structural vertical dividers. Sections are clearly demarcated by 1px horizontal borders. The navigation is a floating-to-fixed transition element with backdrop blur.",
    "prompts": [
      {
        "part": "Structural Grid",
        "prompt": "Create a fixed background layer with vertical lines at 25%, 50%, and 75% width using 1px #e5e4de. Overlay a 40px square grid pattern with a radial transparency mask (40% center opacity, 0% edge opacity)."
      },
      {
        "part": "Header Navigation",
        "prompt": "A fixed top nav starting with 32px padding-top. On scroll, it transitions to a border-bottom fixed bar with #f7f6f2/80 backdrop-blur. The brand logo is a serif 'SUPERDESIGN' in 20px font-size, flanked by two horizontal bars of varying widths (24px and 32px). Links are 10px uppercase Space Mono with 0.3em tracking."
      },
      {
        "part": "Hero Section",
        "prompt": "Center-aligned hero with a pulse-dot badge. The H1 should be massive (9vw), serif, light weight, and uppercase. Use an italicized secondary color (#B4B4B4) for key words. Primary CTA button should be #3d7068 with a 'Space Mono' label that increases character tracking from 0.2em to 0.4em on hover."
      },
      {
        "part": "Statistics Grid",
        "prompt": "A 3-column grid with 1px #e5e4de dividers. Each cell has 40px padding, a 48px bordered icon box, a large serif number (4xl), and an uppercase mono label. Cells transition to a white background on hover."
      },
      {
        "part": "Text Reveal Section",
        "prompt": "A scroll-interactive section where each word of a large serif paragraph (3xl to 6xl) increases opacity from 0.15 to 1.0 as the user scrolls, creating a 'reading' effect."
      },
      {
        "part": "Interactive Workflow",
        "prompt": "Two-column layout. Left side: Vertical steps (01, 02, 03) in mono. Clicking a step expands a description and reduces the opacity of inactive steps to 0.4. Right side: A sticky card with a grayscale image (60% opacity, multiply blend mode) and a 'scan-line' progress bar using #3b82f6."
      },
      {
        "part": "Use Case Tabs",
        "prompt": "A centered tab switcher with pill-shaped buttons. Content below is a large bordered card (#f7f6f2) featuring a massive 240px ghost icon (5% opacity) in the background and a 3-column benefit grid at the bottom."
      },
      {
        "part": "Contact Form",
        "prompt": "Two-column grid. Left side: Large serif heading 'Request Access'. Right side: Form with inputs that are only bottom-bordered (#e5e4de). Placeholder text in 10px mono. Submit button is full-width with 0.4em letter-spacing and a #3d7068 shadow-drop."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Scan-Line Progress Bar",
      "description": "A technical loading indicator used for status updates.",
      "prompt": "Create a 2px height container with #e5e4de background. Inside, a #3b82f6 line that animates from -100% to 100% width/position using a 2s infinite cubic-bezier(0.8, 0, 0.2, 1) 'slide' animation."
    },
    {
      "component": "Animated CTA Button",
      "description": "High-intent button with character-spacing and background-fill transitions.",
      "prompt": "Button with #3d7068 background, #ffffff text, 'Space Mono' font, 10px size, 0.25em tracking. On hover: tracking increases to 0.4em and a white/20% overlay slides up from the bottom (translate-y-full to 0)."
    },
    {
      "component": "Editorial Word Reveal",
      "description": "Scroll-synced typography effect.",
      "prompt": "Split text into individual <span> elements. Set default opacity to 0.15. Using JS IntersectionObserver or scroll listener, map the scroll progress of the container to the index of the spans, setting opacity to 1.0 as they 'activate'."
    }
  ],
  "special_notes": "MUST: Maintain the #f7f6f2 background to avoid a 'clinical' white look. MUST: Use 1px borders instead of shadows for section separation. MUST: Ensure 'Space Mono' is used for all metadata and numeric data. MUST NOT: Use rounded corners larger than 2px. MUST NOT: Use vibrant gradients; stick to solid fills and simple opacity transitions."
}

{
  "summary": "A sophisticated neumorphic administrative dashboard with a focus on tactile interactivity and dynamic, playful animations. It features a responsive layout with a persistent sidebar, a glass-like header, and a grid of interactive stat cards followed by detailed activity and status modules.",
  "style": {
    "description": "The style is 'Neumorphism 2.0' — using light and shadow to create depth. It uses Satoshi for body text and General Sans for headings. Colors are centered around a soft grey base (#e0e5ec) for light mode and a deep navy (#1e2030) for dark mode. Animations are pervasive, using cubic-bezier(0.34, 1.56, 0.64, 1) for a bouncy, premium feel.",
    "prompt": "Create a Neumorphic design system with the following specifications:\n\n### Colors\n- **Light Mode Base:** #e0e5ec (Background & Surface)\n- **Light Mode Shadows:** Light #ffffff, Shadow #a3b1c6\n- **Dark Mode Base:** #1e2030 (Background)\n- **Dark Mode Shadows:** Light #2a2d42, Shadow #14152a\n- **Accents:** Indigo (#6366f1), Emerald (#10b981), Rose (#f43f5e), Violet (#8b5cf6)\n\n### Neumorphic Effects\n- **Flat Surface:** box-shadow: 6px 6px 12px [shadow_var], -6px -6px 12px [light_var].\n- **Inset Surface:** box-shadow: inset 4px 4px 8px [shadow_var], inset -4px -4px 8px [light_var].\n- **Interactive Buttons:** Same as Flat but transitions to Inset on click. Hover: translateY(-2px) scale(1.04).\n\n### Typography\n- **Headings:** 'General Sans', semi-bold (600), tight tracking (-0.02em).\n- **Body:** 'Satoshi', medium (500), font-size: 14px.\n- **Mono:** 'JetBrains Mono' or similar for status logs, font-size: 11px.\n\n### Animations\n- **Timing:** Use cubic-bezier(0.34, 1.56, 0.64, 1) for all transitions.\n- **Stat Counters:** Numbers count up from 0 to target over 1.8s with a final scale pulse.\n- **Floating:** Icons should bob vertically (±5px) over 3s ease-in-out.\n- **Progress Bars:** Include an animated shimmer gradient (waveShimmer) and a constant glow (filter: drop-shadow)."
  },
  "layout_and_structure": {
    "description": "The layout uses a 72w sidebar on desktop, a fixed-height sticky header (72px), and a multi-column responsive grid for main content.",
    "prompts": [
      {
        "part": "Sidebar",
        "prompt": "Design a 288px (w-72) sidebar. Includes a top-aligned logo in a nm-flat card. Navigation links use a 'sidebar-link' style: transparent background by default, transitioning to nm-inset with indigo text (#6366f1) when active. On hover, links should slide 4px right with a subtle background gradient expansion."
      },
      {
        "part": "Header",
        "prompt": "Sticky header with 72px height and nm-flat styling. Contains breadcrumbs on the left, a rounded nm-inset search bar (288px wide) in the center-right, and a circular theme toggle and notification button. All buttons must be nm-button type (40px x 40px rounded-full)."
      },
      {
        "part": "Stat Cards Grid",
        "prompt": "A grid of 4 cards. Each card is nm-flat with nm-flat-hover effect. Features: Top-left floating icon in an nm-inset square; top-right status pill (inset); large bold counter (3xl); trending indicator (+X%) at the bottom. Staggered entrance animation with 100ms delay per card."
      },
      {
        "part": "Main Content Grid",
        "prompt": "Two-column grid for 'Recent Activity' and 'Hardware Pulse'. Activity items are separated by a gradient border (transparent-to-slate-300-to-transparent) and slide in from the left with a bounce. Hardware Pulse uses nm-track progress bars with animated gradient fills."
      },
      {
        "part": "Terminal Component",
        "prompt": "An nm-inset console at the bottom of the status column. Features colored window controls (rose, amber, emerald), monospaced text, and a cursor blink animation. Text lines should reveal sequentially with a 300ms stagger."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Animated Progress Fills",
      "description": "Progress bars with moving gradient stripes and pulsing glow.",
      "prompt": "Implement a 'progress-track' using nm-inset. The 'progress-fill' should be a linear-gradient (e.g., #6366f1 to #a78bfa) with an overlay ::after element running a 'waveShimmer' animation (background-position shift). The fill should have a drop-shadow matching its primary color to simulate a glow."
    },
    {
      "component": "Ripple-Effect Button",
      "description": "A button that generates an expanding radial wave on click.",
      "prompt": "On click, inject a span with .ripple-effect class. Use a radial-gradient(circle, rgba(99,102,241,0.3) 0%, transparent 70%). Animate scale from 0 to 4 and opacity from 0.5 to 0 over 700ms using cubic-bezier(0.4, 0, 0.2, 1)."
    },
    {
      "component": "Floating Stat Icons",
      "description": "Continuous vertical bobbing for stat card visuals.",
      "prompt": "Apply a 'float-icon' class to card icons. Animation: translateY(0) to translateY(-5px) over 3s using cubic-bezier(0.45, 0.05, 0.55, 0.95) with infinite iteration and alternate direction."
    },
    {
      "component": "New Component",
      "description": "",
      "prompt": ""
    }
  ]
}

{
  "summary": "RKI Dashboard Mobile: A minimalist apartment management dashboard for Android. It uses a structured white background, a functional teal accent (#1a9b8e), and clear information hierarchy through a grid-and-list hybrid layout. The design emphasizes 'at-a-glance' data consumption for property owners and managers.",
  "style": {
    "description": "Professional and minimalist style using 'Plus Jakarta Sans'. The palette is dominated by pure white (#FFFFFF), light grays (#F9FAFB), and a vibrant teal (#1a9b8e) for primary actions and highlights. The theme avoids gradients in favor of flat fills, subtle borders, and soft backgrounds. Animations focus on state transitions and hover interactions using standard easing.",
    "prompt": "Create a design system with the following specs: \n- **Typography**: Primary font 'Plus Jakarta Sans'. Headings in Bold/Semi-bold (weight 700/600), body text in Medium (500) or Regular (400). Scale: H1 (20px), Body-Semibold (14px), Body-Regular (12px), Micro-labels (10px).\n- **Color Palette**: \n  - Primary Teal: #1a9b8e\n  - Secondary Teal: #e6f5f3 (50), #ccebe7 (100)\n  - Grayscale: #111827 (900), #6B7280 (500), #9CA3AF (400), #F3F4F6 (100), #F9FAFB (50)\n  - Status: Green-50/700 for 'Occupied', Orange-50/700 for 'Available'\n- **Effects**: Borders: 1px solid #F3F4F6; Radius: 16px (2xl) for cards, 12px (xl) for list items, 8px (lg) for smaller icons. Shadows: Very subtle inner or soft 2px blur drop shadows for list items.\n- **Animation**: Cubic-bezier(0.4, 0, 0.2, 1) for button hover states and icon color transitions."
  },
  "layout_and_structure": {
    "description": "The mobile layout is vertically stacked with a sticky header and a persistent bottom navigation bar. Content sections include a 2-column metrics grid followed by single-column lists.",
    "prompts": [
      {
        "part": "Sticky Header",
        "prompt": "Top-aligned header with 56px height (excluding safe area). Left side contains an app icon (teal square #1a9b8e, 40x40px, 12px radius) with white brand text, followed by a vertical stack: 'Dashboard' (H1, 20px Bold) and a gray subtitle (12px). Right side features a 40px circular notification bell button with a light hover state."
