      },
      {
        "part": "Bottom Navigation",
        "prompt": "A fixed footer with 34px bottom padding for modern OS indicators. Features 3 equally spaced buttons. The active button has a 40px teal-50 circular background and a teal icon/label. Inactive buttons use gray-400 icons and labels (10px font size)."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Featured Metric Card",
      "description": "High-visibility metric card for primary KPIs.",
      "prompt": "Card container with background #e6f5f3 and a 2px solid #1a9b8e border. Inside, top-right features a decorative semi-transparent circle (teal-100 at 50% opacity, -32px offset). The icon background is solid teal-500 with a white icon. All text is themed in teal-700 to ensure contrast and visual distinction from standard metrics."
    },
    {
      "component": "Status Pill Badge",
      "description": "Compact status indicator for list items.",
      "prompt": "A small pill-shaped container (height 20px) with horizontal padding (8px). Uses a subtle background (e.g., Green-50 #f0fdf4) and matching bold text (Green-700 #15803d) at 10px font size. Radius is 9999px (full round)."
    }
  ]
}

{
  "summary": "An ultra-wide, high-octane racing banner with a black background, vibrant neon red highlights, and aggressive italicized typography. The design uses layered animations including motion streaks, glitch overlays, and lightning flashes to create a sense of extreme speed and chaos.",
  "style": {
    "description": "Brutal/Cinematic Racing style using a high-contrast palette of Black (#030303), Neon Red (#ff0040), and White. Typography features heavy weights (900) and italicized headers for speed. Visual effects include 15-degree skews, motion streaks, fire-flicker glows, and digital glitch distortion.",
    "prompt": "Create a design system with a 'Cinematic Underground' theme. Primary Color: Neon Red (#ff0040) with a glow intensity of 20px-50px. Background: Deep Black (#030303) with grayscale, high-contrast photographic textures (200% contrast, 0.2 brightness). Typography: Headers use 'Tanker' or similar heavy-impact sans-serif, italicized, with tight tracking. Body text uses 'Satoshi' or 'Inter' at 900 weight with wide letter spacing (0.4em to 0.6em). Animations: Implement lightning strikes using opacity shifts (95% white flash, 96% neon red flash), and motion streaks using skewed white and red lines (#ff0040) traveling horizontally at 0.6s linear loops. Borders should be sharp, with occasional 4px accent frames on corners."
  },
  "layout_and_structure": {
    "description": "A horizontal wide-aspect layout divided into three main zones: Branding (Left), Feature/Impact (Center), and Action/Socials (Right).",
    "prompts": [
      {
        "part": "Background & Atmospheric Layers",
        "prompt": "Apply a grayscale, high-contrast image of a vehicle or urban environment as the base. Overlay a horizontal gradient (Black -> Transparent -> Black). Add 'Motion Streaks': absolute-positioned lines (h: 1px to 2px, w: 250px+) that animate from right to left with a -45deg skew. Include a 'Fire Layer' at the bottom using blurred (#ff0040) radial gradients with a 0.2s flicker animation."
      },
      {
        "part": "Left: Branding & Identity",
        "prompt": "Position a brand title section. Top element: A 1.5px high horizontal bar in Neon Red (#ff0040) with a pulse animation, followed by sub-header text with 0.6em tracking. Main Title: Huge 8xl font size, black weight, italicized, featuring the primary brand name. Use text-shadow (0 0 50px) to give the text a neon glow."
      },
      {
        "part": "Center: Impact Messaging",
        "prompt": "Place an 'Explosive Title' in the center. Use a bouncing animation on a 6xl italicized font. Background the text with a blurred red glow (#ff0040/20). Below the title, place two icon-text pairs (e.g., speedometers or fire icons) using animated icons that spin or pulse."
      },
      {
        "part": "Right: CTA & Navigation",
        "prompt": "Align elements to the right. Include a 'Sys-Ready' mono-spaced tag at the top. The primary CTA button is a large rectangle skewed at -12deg, filled with Neon Red (#ff0040), featuring a white 4px border-right. Upon hover, the button should transition to white background with black text. Add a social handle (e.g., Discord link) below with a high-tracking font and pulse animation."
      }
    ]
  },
  "special_ui_components": [
    {
      "component": "Skewed Impact Button",
      "description": "A high-intensity action button with motion-skew and sliding hover effect.",
      "prompt": "Shape: Rectangle with transform: skewX(-12deg). Color: #ff0040 background. Shadow: 0 0 60px rgba(255, 0, 64, 0.6). Hover Effect: A white overlay (#FFFFFF/30) slides from left-to-right on hover while the main background transitions to solid white. Typography inside must be heavy weight, all-caps, and italicized."
    },
    {
      "component": "Glitch Overlay",
      "description": "Full-screen or container-level noise and shake effect.",
      "prompt": "A fixed or absolute overlay with a 10px border in 10% opacity Neon Red. Apply a 'glitch-shake' animation using translate transformations (-5px to 5px) every 0.1s. Use 'mix-blend-mode: color-dodge' to make it react with underlying imagery."
    }
  ],
  "special_notes": "MUST maintain the -12 to -15 degree skew on all interactive elements to preserve the sense of forward motion. DO NOT use rounded corners; keep all edges sharp and industrial. MUST use lightning-strike flashes sparingly to avoid visual fatigue, but consistently enough to maintain energy. NOT suitable for light-mode applications."
}

{
  "summary": "A sophisticated single-page portfolio with a deep black theme (#050505), featuring bold geometric typography, high-contrast accent colors (blue, purple, green), and interactive project grids. The UI transitions from a retro pixel-game aesthetic into a clean, modern professional site using scanline overlays and smooth scroll animations.",
  "style": {
    "description": "The style combines retro-tech elements (pixel fonts, scanlines) with high-end modern design (Space Grotesk headers, Inter body text, glassmorphism). It utilizes a monochromatic dark base (#050505) with vibrant gradient accents and subtle 'glow' effects from blurred background containers.",
    "prompt": "Create a design system using a background of #050505 and foreground of #FFFFFF. Typography: Headers in 'Space Grotesk' (Weights: 500, 700, 800) with tight tracking; body text in 'Inter' (Weights: 300, 400). Accent colors: Electric Blue (#3B82F6), Deep Purple (#9333EA), and Signal Green (#22C55E). Include a CRT-style scanline overlay (linear-gradient 50% transparency every 4px). Use glassmorphism for containers: background white/5, border white/10, backdrop-blur(12px). Animations should use cubic-bezier(0.4, 0, 0.2, 1) for smooth transitions."
  },
  "layout_and_structure": {
    "description": "A vertical-scrolling single-page application consisting of a fixed navigation bar, hero section, interactive marquee, asymmetrical project grid, and a split-section services/about layout.",
    "prompts": [
      {
        "part": "Navigation",
        "prompt": "Fixed top bar, height: 80px. Background: #050505 at 80% opacity with backdrop-blur. Left: Logotype in Space Grotesk with a single color dot. Right: Text links (14px, uppercase, tracking-wide) in #9CA3AF. Far right: Pill-shaped CTA button with black text on white background."
      },
      {
        "part": "Hero Section",
        "prompt": "Min-height 100vh. Center-aligned text. Hero tag: Small pill with 'Press Start 2P' font and green dot. Main Heading: Font size 5xl (mobile) to 8xl (desktop), font Space Grotesk, leading-0.95. One word should be a gradient (Blue to Purple). Subtext: Max-width 640px, Inter font, #9CA3AF color. Buttons: Pair a solid white pill-button with an outlined (border-white/20) ghost button."
      },
      {
        "part": "Skills Marquee",
        "prompt": "Full-width container, height: 80px-120px. Background: #0a0a0a. Continuous scrolling text (animate-marquee 20s linear infinite). Text: Space Grotesk, bold, transparent with a gray-to-black gradient stroke, font-size 4xl to 6xl."
      },
      {
        "part": "Project Grid",
        "prompt": "Max-width 1280px. 2-column grid with alternating vertical offsets (top margin 64px on even items). Cards: Aspect ratio 4:3, border-radius 16px, overflow hidden. Hover state: Image scales 1.05x, black overlay appears (60% opacity) with a white circular icon in the center. Card metadata: Title in Space Grotesk 2xl, tech tags as small white/5 border-radius pills."
      },
      {
        "part": "About and Services",
        "prompt": "Split layout (1/3 image, 2/3 text). Image: Grayscale, fixed aspect ratio 1:1, border-radius 16px. Content: Large introductory paragraph (Inter, 20px, light). Services Grid: 2x2 grid of cards with glassmorphism borders. Icons: Use monochrome Lucide-style icons with specific brand colors (Blue, Purple, Green, Pink)."
      },
      {
